import numpy as np

def ablate_n_rounds(
    model,
    constitution: list,
    test_prompts: list[str],
    harm_classifier,
    helpfulness_classifier,
    max_rounds: int = 5,
) -> dict:
    """
    Measure harm rate and helpfulness score as a function of revision rounds.
    Useful for picking the optimal n_rounds for your use case.
    """
    import random
    results = {r: {'harm': [], 'helpful': []} for r in range(max_rounds + 1)}

    for prompt in test_prompts:
        current = model.generate(prompt, temperature=0.8)
        # Round 0: initial response
        results[0]['harm'].append(harm_classifier.score(current))
        results[0]['helpful'].append(helpfulness_classifier.score(current))

        for r in range(1, max_rounds + 1):
            principle = random.choice(constitution)
            critique = model.generate(
                CRITIQUE_PROMPT.format(
                    original_prompt=prompt, initial_response=current,
                    principle=principle.critique_form
                ), temperature=0
            )
            if "no issues" in critique.lower():
                # Copy previous round's scores if no change
                results[r]['harm'].append(results[r-1]['harm'][-1])
                results[r]['helpful'].append(results[r-1]['helpful'][-1])
                continue
            current = model.generate(
                REVISION_PROMPT.format(
                    original_prompt=prompt, initial_response=current, critique=critique
                ), temperature=0.3
            )
            results[r]['harm'].append(harm_classifier.score(current))
            results[r]['helpful'].append(helpfulness_classifier.score(current))

    return {
        r: {
            'mean_harm': np.mean(v['harm']),
            'mean_helpful': np.mean(v['helpful']),
        }
        for r, v in results.items()
    }
# Typical result: harm drops sharply from round 0 to 1, then plateaus.
# Helpfulness is flat or slightly decreasing. Optimal n_rounds is usually 1.
